//vikingbrothersgym.github.io/vikingbrothersgym/assets/todos-CQQ-Teft.webp",LR="https://vikingbrothersgym.github.io/vikingbrothersgym/assets/gimnasio_exterior-H6J1WoM0.webp",MR=({title:e,description:t,image:n})=>y.jsxs("div",{className:"card",children:[y.jsx("img",{src:n,alt:e}),y.jsxs("div",{className:"card-content",children:[y.jsx("h3",{children:e}),y.jsx("p",{children:t})]})]}),OR=()=>{const e=[{title:"Clases dirigidas",description:"Todas ellas están incluidas en la cuota. Consulta los horarios en esta web y ¡entrena!",image:e4},{title:"Templo Old School",description:"Ven y descubre nuestra sala de clases y musculación al puro estilo Old School",image:LR},{title:"Asesoría Vikinga",description:"Nuestros entrenadores personales del Templo te llevarán a alcanzar tus objetivos. Ven y pregúntanos sin ningún compromiso. ¡Estamos para ayudarte!",image:TR},{title:"Boxeo",description:"Clases de Boxeo y Boxeo infantil. ¡Consulta horarios en esta web o ven a preguntarnos!",image:ER},{title:"Familia",description:"Somos un gimnasio de barrio familiar. El buen rollo es un sello distintivo",image:CR},{title:"Para todos",description:"Diseñado para personas de todas las edades y niveles de condición física. ¡Estaremos encantados de recibirte!",image:kR}];return y.jsxs("section",{id:"servicios",className:"flex flex-col items-center justify-center box-border mb-[50px] w-full px-7",children:[y.jsxs("h1",{className:"sec-tit",children:["TRANSFORMA",y.jsx("span",{children:" TU RUTINA "})]}),y.jsx("div",{className:"grid w-full gap-7 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",children:e.map((t,n)=>y.jsx(MR,{title:t.title,description:t.description,image:t.image},n))})]})},na=[{id:18,image:"/vikingbrothersgym/news/new18.webp",title:"❗ Cancelación del Seminario Femenino de Defensa Personal",date:"21/01/2026",text:["Informamos que el seminario femenino de defensa personal previsto para mañana ha sido cancelado por motivos personales.","Lamentamos las molestias que esto pueda ocasionar y agradecemos vuestra comprensión.","Próximamente comunicaremos una nueva fecha para la realización del seminario.","Para cualquier duda o consulta, podéis contactar con nosotros directamente."]},{id:17,image:"/vikingbrothersgym/news/new17.webp",title:"🥊 ¡Nuevas clases de Boxeo Infantil a partir de febrero!",date:"21/01/2026",text:["En febrero comenzamos con una nueva actividad pensada para los más pequeños: Boxeo Infantil de Iniciación, dirigida a niños y niñas de entre 5–6 años hasta 12–13 años.","Las clases estarán enfocadas en el aprendizaje progresivo del boxeo, siempre de forma segura y adaptada a cada edad. Se trabajarán técnicas básicas, coordinación y condición física a través de juegos, ejercicios dinámicos y trabajo con saco, fomentando la diversión y la confianza. ❌ No habrá sparring, priorizando en todo momento la seguridad, el respeto y el desarrollo personal de los niños.","🗓 Horario: Miércoles de 17:30 a 18:30","🥊 ¿Qué trabajamos en las clases? Técnicas de aprendizaje, juegos y saco (sin sparring)","💶 Precio: 25 € al mes","Una actividad ideal para que los más pequeños se inicien en el deporte, aprendan disciplina y disfruten del ejercicio en un entorno controlado y motivador.","📩 Plazas limitadas","Para más información o inscripciones, contacta con nosotros o pásate por el gimnasio.","¡Te esperamos para empezar febrero a lo grande! 💪"]},{id:16,image:"/vikingbrothersgym/news/new16.webp",title:"🥋 Seminario de Krav Magá en Viking Brother Gym – 13 de Diciembre",date:"08/12/2025",text:["El próximo 13 de diciembre, Viking Brother Gym acogerá un seminario exclusivo de Krav Magá, una disciplina enfocada en la defensa personal femenina y el desarrollo de habilidades para prevenir y afrontar situaciones de peligro real.","La actividad será dirigida por José A. Ramos, Instructor y Árbitro Nacional de la Federación Española de Lucha (F.E.L.), reconocido por su amplia experiencia en técnicas de defensa personal, especialmente frente a amenazas como agresiones con cuchillo o agarres.","🕒 Horario: De 10:00 h a 12:30 h","📍 Lugar: Viking Brother Gym, C/ Miraflores 12-14, Zaragoza","💶 Precio: 25 €","📋 Inscripciones: En la recepción del gimnasio.","Este seminario está orientado especialmente a mujeres, pero es abierto a todo el público interesado en mejorar su autoestima, su preparación física y su capacidad de respuesta ante situaciones de riesgo.","¡No te lo pierdas! Una oportunidad única para entrenar con un profesional de primer nivel y aprender técnicas reales de defensa que pueden marcar la diferencia."]},{id:15,image:"/vikingbrothersgym/news/new15.webp",title:"🥋 Seminario de Krav Magá en Viking Brother Gym – 18 de Octubre",date:"20/09/2025",text:["El próximo 18 de octubre, Viking Brother Gym acogerá un seminario exclusivo de Krav Magá, una disciplina enfocada en la defensa personal femenina y el desarrollo de habilidades para prevenir y afrontar situaciones de peligro real.","La actividad será dirigida por José A. Ramos, Instructor y Árbitro Nacional de la Federación Española de Lucha (F.E.L.), reconocido por su amplia experiencia en técnicas de defensa personal, especialmente frente a amenazas como agresiones con cuchillo o agarres.","🕒 Horario: De 10:00 h a 13:00 h","📍 Lugar: Viking Brother Gym, C/ Miraflores 12-14, Zaragoza","💶 Precio: 30 €","📋 Inscripciones: En la recepción del gimnasio.","Este seminario está orientado especialmente a mujeres, pero es abierto a todo el público interesado en mejorar su autoestima, su preparación física y su capacidad de respuesta ante situaciones de riesgo.","¡No te lo pierdas! Una oportunidad única para entrenar con un profesional de primer nivel y aprender técnicas reales de defensa que pueden marcar la diferencia."]},{id:14,image:"/vikingbrothersgym/news/new14.webp",title:"🥊 ¡Vuelven las Clases de Boxeo en Viking Brothers Gym!",date:"31/08/2025",text:["Nos alegra anunciar que a partir del lunes 1 de septiembre se reanudan las clases de Boxeo con nuestro profesor Fran Marquino, quien regresa para seguir formando y motivando a todos los apasionados de este deporte.","📅 Horarios de las clases:","- Lunes y Miércoles: 19:00 – 20:00","- Martes y Jueves: 19:00 – 20:00 y 20:30 – 21:30","El boxeo es una de las disciplinas más completas: mejora la resistencia, la fuerza, la coordinación y la disciplina mental. Tanto si eres principiante como si ya tienes experiencia, encontrarás un entrenamiento adaptado a tu nivel.","👉 ¡No pierdas la oportunidad de entrenar con un gran profesional y llevar tu boxeo al siguiente nivel en Viking Brothers Gym!"]},{id:13,image:"/vikingbrothersgym/news/new13.webp",title:"🥋💥¡Nuevo! Krav Magá y Defensa Personal",date:"30/08/2025",text:["🥋💥 ¡Nuevas Clases de Krav Magá y Defensa Personal en Viking Brothers Gym! 💥🥋","Nos complace anunciar que a partir de la segunda quincena de septiembre incorporamos a nuestra programación las clases de Krav Magá y Defensa Personal, impartidas por José Ramos, profesor federado y experto en estas disciplinas.","📅 Días: Lunes y Miércoles","⏰ Horario: 10:00 a 11:00","El Krav Magá es un sistema de defensa personal reconocido por su efectividad y practicidad en situaciones reales. Una oportunidad única para mejorar tu seguridad, confianza y condición física con la guía de un instructor cualificado.","👉 ¡Reserva tu plaza y forma parte de esta nueva experiencia en Viking Brothers Gym!"]},{id:12,image:"/vikingbrothersgym/news/new12.webp",title:"Descanso Yoga: Volvemos en Septiembre",date:"10/07/2025",text:["Querida comunidad de Viking Brothers Gym:","Les informamos que durante los meses de verano no habrá clases de yoga, ya que nuestro equipo tomará un merecido descanso.","⛱️ Pausa de verano: Julio y agosto","📅 Reanudación de clases: 2 de septiembre","Agradecemos su comprensión y esperamos que disfruten del verano. ¡Nos vemos renovados en septiembre para seguir fortaleciendo cuerpo y mente juntos!","El equipo de Viking Brothers Gym 🧘‍♂️💪"]},{id:11,image:"/vikingbrothersgym/news/new11.webp",title:"🥋 Seminario de Krav Magá en Viking Brother Gym – 21 de Junio",date:"22/05/2025",text:["El próximo 21 de junio, Viking Brother Gym acogerá un seminario exclusivo de Krav Magá, una disciplina enfocada en la defensa personal femenina y el desarrollo de habilidades para prevenir y afrontar situaciones de peligro real.","La actividad será dirigida por José A. Ramos, Instructor y Árbitro Nacional de la Federación Española de Lucha (F.E.L.), reconocido por su amplia experiencia en técnicas de defensa personal, especialmente frente a amenazas como agresiones con cuchillo o agarres.","🕒 Horario: De 10:00 h a 12:30 h","📍 Lugar: Viking Brother Gym, C/ Miraflores 12-14, Zaragoza","💶 Precio: 20 €","📋 Inscripciones: En la recepción del gimnasio.","Este seminario está orientado especialmente a mujeres, pero es abierto a todo el público interesado en mejorar su autoestima, su preparación física y su capacidad de respuesta ante situaciones de riesgo.","¡No te lo pierdas! Una oportunidad única para entrenar con un profesional de primer nivel y aprender técnicas reales de defensa que pueden marcar la diferencia."]},{id:10,image:"/vikingbrothersgym/news/new10.webp",title:"💪🔥 ¡La Batalla Ha Comenzado en Viking Brothers Gym! 🔥💪",date:"25/03/2025",text:["En Viking Brothers Gym, cada entrenamiento es una oportunidad para superarte. Nos enfocamos en brindar el mejor ambiente, equipo y motivación para que logres tus objetivos físicos y mentales.","🔹 Entrenamiento para Todos 🏋️‍♂️","No importa tu nivel, aquí encontrarás el espacio perfecto para mejorar tu fuerza, resistencia y bienestar.","🔹 Unidos por la Disciplina ⚔️","Forma parte de una comunidad que te impulsa a dar lo mejor de ti en cada sesión.","🔹 Siente el Espíritu Viking 🛡️","Sumérgete en una atmósfera llena de energía y determinación, donde cada entrenamiento es un paso más hacia tu mejor versión.","👉 ¿Listo para el desafío? Ven a entrenar con nosotros y forja tu propio camino. ¡Nos vemos en Viking Brothers Gym! 💀🔥"]},{id:9,image:"/vikingbrothersgym/news/new9.webp",title:"¡No dejes pasar tu Drakkar!",date:"02/03/2025",text:["Si has llegado hasta aquí, estás de suerte.","En nuestro Templo te ofrecemos una gran variedad de servicios: sala de musculación, clases dirigidas, entrenadores personales que te llevarán al máximo nivel, y Boxeo y Kick Boxing.","Pero esto no es lo mejor: ¡hazlo por tan solo 27.50€ al mes!","¿De verdad estás dudando? Consulta para más informaciín en esta web y/o acércate al gimnasio para contarte más sobre él."]},{id:5,image:"/vikingbrothersgym/news/new5.jpeg",title:"Nuestra campeona de boxeo del templo",date:"11/11/2024",text:["Tenemos el placer de tener con nosotros a Andrea Marquino.","Esta campeona vikinga es un diamante del boxeo aragonés.","¿Sabías que también entrena y da clases junto con su padre en el Viking Brothers Gym?","Consulta en esta web y/o ven a preguntarnos para saber más. ¡Apúntate a nuestras clases tengas el nivel que tengas!"]},{id:1,image:"/vikingbrothersgym/news/new1.png",title:"Web Viking Brothers Gym Zaragoza",date:"13/08/2024",text:["En Viking Brothers Gym, hemos creado esta página web para ofrecerte una experiencia completa y conveniente, reflejando la energía y la dedicación que nos caracteriza.","  - Explora nuestras Clases y Servicios: Desde entrenamientos de fuerza y resistencia hasta clases especializadas, tenemos una amplia variedad de opciones diseñadas para todos los niveles y objetivos.","  - Conoce a Nuestros Entrenadores: Nuestro equipo de profesionales está aquí para guiarte en cada paso del camino. Navega por nuestra sección de Clases para descubrir más sobre las personas que estarán contigo en cada repetición, motivándote a alcanzar tus metas.","  - Planifica Tu Visita: Nuestra web te permite reservar clases, consultar horarios, e incluso planificar entrenamientos personalizados. Todo lo que necesitas está a solo un clic de distancia.","  - Mantente Informado: Accede a las últimas noticias, promociones y eventos especiales directamente desde nuestra página. Ya sea una nueva clase, un reto de fitness o una oferta exclusiva, serás el primero en enterarte.","  - Únete a Nuestra Comunidad: Conecta con nosotros a través de nuestras redes sociales y mantente en contacto con otros miembros. Comparte tus progresos y sé parte de una comunidad que se apoya mutuamente.","Tu viaje hacia un estilo de vida más saludable comienza aquí. Explora nuestra web, conoce nuestros servicios y déjanos ayudarte a alcanzar tus objetivos de fitness con pasión y profesionalismo."]}],gu=({ultimas:e,not:t})=>(Wc(),y.jsxs(_9,{as:q3,to:`${Ct.root}noticia/${t.id}`,className:"w-full bg-zinc-900 max-w-sm shadow-lg rounded-2xl hover:opacity-100 hover:scale-[1.02] cursor-pointer animate-fadeIn",children:[y.jsx(Vo,{alt:t.title,src:t.image,className:"object-cover rounded-t-2xl w-full"}),y.jsx(v9,{className:"w-full p-0",children:y.jsx("h3",{className:"px-5 text-lg font-semibold text-third",children:t.title})}),y.jsx(y9,{className:"p-4 pt-0 text-base text-gray-300 font-bold",children:t.date})]})),AR=()=>{const e=P.useRef(null),[t,n]=P.useState(0);return P.useEffect(()=>{if(!e.current)return;const r=new ResizeObserver(i=>{for(let s of i)n(s.contentRect.width)});return r.observe(e.current),()=>r.disconnect()},[]),y.jsxs("div",{className:"ult-container",children:[y.jsxs("h1",{className:"sec-tit pt-5",children:["ÚLTIMAS ",y.jsx("span",{children:" NOTICIAS "})]}),y.jsxs("div",{ref:e,className:"w-full grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 justify-items-center gap-5 box-border px-5 py-5",children:[y.jsx(gu,{ultimas:!0,not:na[0]}),y.jsx(gu,{ultimas:!0,not:na[1]}),t>1024&&y.jsx(gu,{ultimas:!0,not:na[2]})]})]})},IR="https://vikingbrothersgym.github.io/vikingbrothersgym/assets/Andrea-ktMFKJH-.webp",$R="https://vikingbrothersgym.github.io/vikingbrothersgym/assets/Lucia-DBAs7DfH.webp",NR="https://vikingbrothersgym.github.io/vikingbrothersgym/assets/Tatiana-Czoc7pw0.webp",RR=()=>{const e=[{image:IR,name:"ANDREA MARQUINO",text:"Boxeadora selección auto